ee:variables.ee:set-variable:
%dw 2.0
output application/java
import * from dw::core::Strings

fun classifyIntent(query) = 
  query as String toLowerCase() match {
    case q if (q contains "bill" or q contains "payment" or q contains "cost" or q contains "charge") -> {
      category: "billing",
      confidence: 0.9,
      entities: extractBillingEntities(q)
    }
    case q if (q contains "usage" or q contains "consumption" or q contains "kwh" or q contains "energy") -> {
      category: "usage", 
      confidence: 0.85,
      entities: extractUsageEntities(q)
    }
    case q if (q contains "outage" or q contains "power out" or q contains "blackout" or q contains "restoration") -> {
      category: "outage",
      confidence: 0.95,
      entities: extractOutageEntities(q)
    }
    case q if (q contains "save" or q contains "efficient" or q contains "reduce" or q contains "tips") -> {
      category: "efficiency",
      confidence: 0.8,
      entities: extractEfficiencyEntities(q)
    }
    case q if (q contains "service" or q contains "request" or q contains "appointment" or q contains "technician") -> {
      category: "service",
      confidence: 0.85,
      entities: extractServiceEntities(q)
    }
    else -> {
      category: "general",
      confidence: 0.6,
      entities: {}
    }
  }

fun extractBillingEntities(query) = {
  period: if (query contains "last month" or query contains "previous") "last_month"
         else if (query contains "current" or query contains "this month") "current"
         else null,
  amount: if (query contains "how much" or query contains "total") true else false
}

fun extractUsageEntities(query) = {
  period: if (query contains "yesterday") "yesterday"
         else if (query contains "last week") "last_week" 
         else if (query contains "last month") "last_month"
         else "current",
  comparison: query contains "compare" or query contains "vs" or query contains "difference"
}

fun extractOutageEntities(query) = {
  location: if (query contains "my area" or query contains "neighborhood") "customer_area" else null,
  status: if (query contains "when" or query contains "estimate") "restoration_time" else null
}

fun extractEfficiencyEntities(query) = {
  focus: if (query contains "heating" or query contains "cooling" or query contains "hvac") "hvac"
        else if (query contains "appliance") "appliances"
        else if (query contains "solar") "solar"
        else "general"
}

fun extractServiceEntities(query) = {
  type: if (query contains "repair" or query contains "fix") "repair"
       else if (query contains "install") "installation" 
       else if (query contains "maintenance") "maintenance"
       else "general"
}

---
classifyIntent(vars.query)

