ee:message.ee:set-payload:
%dw 2.0 output application/json
fun generateFallbackResponse(intent, responseData) = intent.category match { case "billing" -> "I found your billing information. Your current bill is $" ++ responseData.data.currentBill.amount ++ " and is due on " ++ responseData.data.currentBill.dueDate ++ "." case "usage" -> "Your energy usage for the selected period is " ++ responseData.data.usage.totalKwh ++ " kWh with a daily average of " ++ responseData.data.usage.dailyAverage ++ " kWh." case "outage" -> if (sizeOf(responseData.data) > 0) "I found " ++ sizeOf(responseData.data) ++ " active outage(s) in your area." else "There are no active outages affecting your area." case "efficiency" -> "I have personalized energy saving recommendations for you that could save you up to $" ++ responseData.data.recommendations.insights.totalPotentialSavings ++ " annually." case "service" -> "I can help you with various service requests including repairs, installations, and maintenance. What type of service do you need?" else -> "I'm here to help with your utility account. You can ask me about your bill, energy usage, outages, or request services." }
--- { response: generateFallbackResponse(vars.intent, vars.responseData), actions: vars.responseData.actions, data: vars.responseData.data, followUpQuestions: [ "Would you like to see more details?", "Is there anything else I can help you with?" ] }

%dw 2.0
output application/json
---
{
  preferences: if (sizeOf(payload) > 0) {
    billReminders: payload[0].bill_reminders as Boolean,
    outageAlerts: payload[0].outage_alerts as Boolean,
    usageAlerts: payload[0].usage_alerts as Boolean,
    savingsTips: payload[0].savings_tips as Boolean,
    channels: ([] 
      ++ (if (payload[0].email_enabled as Boolean) ["email"] else [])
      ++ (if (payload[0].sms_enabled as Boolean) ["sms"] else [])
      ++ (if (payload[0].push_enabled as Boolean) ["push"] else [])
    )
  } else {
    billReminders: true,
    outageAlerts: true,
    usageAlerts: false,
    savingsTips: true,
    channels: ["email"]
  }
}
